use std::io;
use std::str::Chars;

fn main() {
    let mut counter = 0;
    let mut col_checked = false;

    for i in 0..8 {
        let mut input_text = String::new();
        io::stdin()
            .read_line(&mut input_text)
            .expect("failed to read from stdin");

        let trimmed = input_text.trim();
        if (trimmed.eq("BBBBBBBB")) {
            counter = counter + 1;
            continue;
        }

        if (col_checked) {
            continue;
        }

        col_checked = true;
        for j in 0..8 {
            let char_at = trimmed.as_bytes()[j];
            if ((char_at as char) == 'B') {
                counter = counter + 1;
            }
        }
    }

    println!("{}", counter);
}
